formulas.expression:
IF( 
{!$Record.Account.IsPersonAccount} = TRUE, 
'IR 35 tool Implementation - ' + {!$Record.Account.FirstName} + ' ' + {!$Record.Account.LastName} , 
'IR 35 tool Implementation - ' + {!$Record.Account.Name}
)

textTemplates.text:
Dear Underwriting team,
Please check whether RICS endorsement required for the below account:
Account Name: {!$Record.Account.FirstName} {!$Record.Account.LastName}
Opportunity: {!$Record.Name}
